{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "今日",
      "route": "pages/Home",
      "tabId": "tab-today",
      "semanticTargets": [
        {
          "id": "home-greeting",
          "role": "assertion",
          "binding": "/greeting"
        },
        {
          "id": "home-today-date",
          "role": "assertion",
          "binding": "/today/date"
        },
        {
          "id": "home-decision-card",
          "role": "assertion",
          "binding": "/today/dish"
        },
        {
          "id": "home-spin-button",
          "role": "action",
          "event": "navigate-to-spin"
        },
        {
          "id": "home-filter-button",
          "role": "action",
          "event": "navigate-to-filter"
        },
        {
          "id": "home-fridge-shortcut",
          "role": "action",
          "event": "navigate-to-fridge"
        },
        {
          "id": "home-recent-checkin-list",
          "role": "list",
          "binding": "/checkins/recent",
          "itemIdPattern": "home-recent-checkin-{id}",
          "emptyStateId": "home-empty-recent-checkin"
        }
      ]
    },
    {
      "id": "spin-page",
      "surfaceId": "spin",
      "pageId": "spin-page",
      "name": "转盘抽菜",
      "route": "pages/Spin",
      "semanticTargets": [
        {
          "id": "spin-wheel",
          "role": "assertion",
          "binding": "/spin/wheel-segments"
        },
        {
          "id": "spin-start-button",
          "role": "action",
          "event": "spin-start"
        },
        {
          "id": "spin-result-banner",
          "role": "assertion",
          "binding": "/spin/result"
        },
        {
          "id": "spin-confirm-button",
          "role": "action",
          "event": "spin-confirm-dish"
        },
        {
          "id": "spin-again-button",
          "role": "action",
          "event": "spin-again"
        },
        {
          "id": "spin-close-button",
          "role": "action",
          "event": "navigate-back"
        }
      ]
    },
    {
      "id": "fridge-page",
      "surfaceId": "fridge",
      "pageId": "fridge-page",
      "name": "冰箱",
      "route": "pages/Fridge",
      "tabId": "tab-fridge",
      "semanticTargets": [
        {
          "id": "fridge-ingredient-input",
          "role": "input",
          "event": "ingredient-input-change"
        },
        {
          "id": "fridge-add-button",
          "role": "action",
          "event": "ingredient-add"
        },
        {
          "id": "fridge-ingredient-list",
          "role": "list",
          "binding": "/fridge/ingredients",
          "itemIdPattern": "fridge-ingredient-{id}",
          "emptyStateId": "fridge-empty-ingredients"
        },
        {
          "id": "fridge-clear-button",
          "role": "action",
          "event": "ingredient-clear-all"
        },
        {
          "id": "fridge-recommend-button",
          "role": "action",
          "event": "fridge-recommend"
        }
      ]
    },
    {
      "id": "filter-page",
      "surfaceId": "filter",
      "pageId": "filter-page",
      "name": "筛选",
      "route": "pages/Filter",
      "semanticTargets": [
        {
          "id": "filter-mood-happy",
          "role": "input",
          "event": "filter-mood-select",
          "context": { "mood": "happy" }
        },
        {
          "id": "filter-mood-tired",
          "role": "input",
          "event": "filter-mood-select",
          "context": { "mood": "tired" }
        },
        {
          "id": "filter-mood-indulgent",
          "role": "input",
          "event": "filter-mood-select",
          "context": { "mood": "indulgent" }
        },
        {
          "id": "filter-mood-light",
          "role": "input",
          "event": "filter-mood-select",
          "context": { "mood": "light" }
        },
        {
          "id": "filter-mood-rushed",
          "role": "input",
          "event": "filter-mood-select",
          "context": { "mood": "rushed" }
        },
        {
          "id": "filter-meal-breakfast",
          "role": "input",
          "event": "filter-meal-select",
          "context": { "meal": "breakfast" }
        },
        {
          "id": "filter-meal-lunch",
          "role": "input",
          "event": "filter-meal-select",
          "context": { "meal": "lunch" }
        },
        {
          "id": "filter-meal-dinner",
          "role": "input",
          "event": "filter-meal-select",
          "context": { "meal": "dinner" }
        },
        {
          "id": "filter-meal-supper",
          "role": "input",
          "event": "filter-meal-select",
          "context": { "meal": "supper" }
        },
        {
          "id": "filter-difficulty-easy",
          "role": "input",
          "event": "filter-difficulty-select",
          "context": { "difficulty": "easy" }
        },
        {
          "id": "filter-difficulty-normal",
          "role": "input",
          "event": "filter-difficulty-select",
          "context": { "difficulty": "normal" }
        },
        {
          "id": "filter-difficulty-hard",
          "role": "input",
          "event": "filter-difficulty-select",
          "context": { "difficulty": "hard" }
        },
        {
          "id": "filter-taste-spicy",
          "role": "input",
          "event": "filter-taste-toggle",
          "context": { "taste": "spicy" }
        },
        {
          "id": "filter-taste-sweet",
          "role": "input",
          "event": "filter-taste-toggle",
          "context": { "taste": "sweet" }
        },
        {
          "id": "filter-taste-sour",
          "role": "input",
          "event": "filter-taste-toggle",
          "context": { "taste": "sour" }
        },
        {
          "id": "filter-taste-savory",
          "role": "input",
          "event": "filter-taste-toggle",
          "context": { "taste": "savory" }
        },
        {
          "id": "filter-apply-button",
          "role": "action",
          "event": "filter-apply"
        },
        {
          "id": "filter-reset-button",
          "role": "action",
          "event": "filter-reset"
        },
        {
          "id": "filter-close-button",
          "role": "action",
          "event": "navigate-back"
        }
      ]
    },
    {
      "id": "result-page",
      "surfaceId": "result",
      "pageId": "result-page",
      "name": "推荐结果",
      "route": "pages/Result",
      "semanticTargets": [
        {
          "id": "result-header",
          "role": "assertion",
          "binding": "/result/summary"
        },
        {
          "id": "result-dish-list",
          "role": "list",
          "binding": "/result/dishes",
          "itemIdPattern": "result-dish-{id}",
          "emptyStateId": "result-empty-state"
        },
        {
          "id": "result-refresh-button",
          "role": "action",
          "event": "result-refresh"
        },
        {
          "id": "result-close-button",
          "role": "action",
          "event": "navigate-back"
        }
      ]
    },
    {
      "id": "checkin-page",
      "surfaceId": "checkin",
      "pageId": "checkin-page",
      "name": "打卡",
      "route": "pages/Checkin",
      "tabId": "tab-checkin",
      "semanticTargets": [
        {
          "id": "checkin-streak-count",
          "role": "assertion",
          "binding": "/checkin/streak"
        },
        {
          "id": "checkin-calendar",
          "role": "assertion",
          "binding": "/checkin/calendar"
        },
        {
          "id": "checkin-today-card",
          "role": "assertion",
          "binding": "/checkin/today"
        },
        {
          "id": "checkin-add-button",
          "role": "action",
          "event": "checkin-add-open"
        },
        {
          "id": "checkin-history-list",
          "role": "list",
          "binding": "/checkin/history",
          "itemIdPattern": "checkin-history-{id}",
          "emptyStateId": "checkin-empty-history"
        },
        {
          "id": "checkin-share-button",
          "role": "action",
          "event": "navigate-to-share"
        }
      ]
    },
    {
      "id": "share-page",
      "surfaceId": "share",
      "pageId": "share-page",
      "name": "分享卡片",
      "route": "pages/Share",
      "semanticTargets": [
        {
          "id": "share-card-preview",
          "role": "assertion",
          "binding": "/share/card"
        },
        {
          "id": "share-save-button",
          "role": "action",
          "event": "share-save-image"
        },
        {
          "id": "share-system-button",
          "role": "action",
          "event": "share-system"
        },
        {
          "id": "share-close-button",
          "role": "action",
          "event": "navigate-back"
        }
      ]
    }
  ],
  "events": [
    { "name": "navigate-to-spin", "description": "Open the spin wheel page from home." },
    { "name": "navigate-to-filter", "description": "Open the filter page/sheet from home." },
    { "name": "navigate-to-fridge", "description": "Open the fridge tab/page." },
    { "name": "navigate-to-share", "description": "Open the share card page/sheet." },
    { "name": "navigate-back", "description": "Close current sheet/page and return." },
    { "name": "spin-start", "description": "Start spinning the wheel." },
    { "name": "spin-confirm-dish", "description": "Confirm the spun dish as today's choice." },
    { "name": "spin-again", "description": "Spin the wheel again." },
    { "name": "ingredient-input-change", "description": "Ingredient text input changed." },
    { "name": "ingredient-add", "description": "Add the current ingredient to the fridge list." },
    { "name": "ingredient-clear-all", "description": "Remove all ingredients from the fridge list." },
    { "name": "fridge-recommend", "description": "Recommend dishes based on fridge ingredients." },
    { "name": "filter-mood-select", "description": "Select a mood filter option." },
    { "name": "filter-meal-select", "description": "Select a meal time option." },
    { "name": "filter-difficulty-select", "description": "Select a difficulty level." },
    { "name": "filter-taste-toggle", "description": "Toggle a taste tag." },
    { "name": "filter-apply", "description": "Apply selected filters and show results." },
    { "name": "filter-reset", "description": "Reset all filter options." },
    { "name": "result-refresh", "description": "Refresh result list with a new random seed." },
    { "name": "checkin-add-open", "description": "Open the add-checkin form/sheet." },
    { "name": "share-save-image", "description": "Save the share card as an image." },
    { "name": "share-system", "description": "Open system share sheet with the card." }
  ],
  "bindings": {
    "/greeting": { "type": "string", "description": "Time-aware greeting text, e.g. 早安." },
    "/today/date": { "type": "string", "description": "Formatted today's date." },
    "/today/dish": { "type": "object", "description": "Today's selected dish object with name, tags, image hint." },
    "/checkins/recent": { "type": "array", "description": "Recent check-in records for home strip." },
    "/spin/wheel-segments": { "type": "array", "description": "Array of dish names on the wheel." },
    "/spin/result": { "type": "object|null", "description": "The dish result after spinning." },
    "/fridge/ingredients": { "type": "array", "description": "List of ingredient strings." },
    "/result/summary": { "type": "string", "description": "Short summary of applied filter or ingredient count." },
    "/result/dishes": { "type": "array", "description": "Filtered or recommended dish list." },
    "/checkin/streak": { "type": "number", "description": "Current consecutive check-in days." },
    "/checkin/calendar": { "type": "array", "description": "Month calendar days with check-in status." },
    "/checkin/today": { "type": "object|null", "description": "Today's check-in record if exists." },
    "/checkin/history": { "type": "array", "description": "Full check-in history list." },
    "/share/card": { "type": "object", "description": "Share card payload with dish, date, streak, theme." }
  },
  "testTargets": {
    "tab-today": { "type": "tab", "label": "今日" },
    "tab-fridge": { "type": "tab", "label": "冰箱" },
    "tab-checkin": { "type": "tab", "label": "打卡" },
    "home-spin-button": { "type": "button", "label": "转盘抽菜" },
    "home-filter-button": { "type": "button", "label": "筛选" },
    "fridge-recommend-button": { "type": "button", "label": "看看能做什么" },
    "filter-apply-button": { "type": "button", "label": "应用筛选" },
    "spin-start-button": { "type": "button", "label": "开始转盘" },
    "checkin-add-button": { "type": "button", "label": "今日打卡" },
    "share-save-button": { "type": "button", "label": "保存卡片" }
  }
}

